"""Централизованное логирование."""from __future__ import annotationsimport loggingfrom logging.handlers import RotatingFileHandlerfrom .config import CONFIGfrom .paths import LOGS_DIR_configured = False_FORMAT = "%(asctime)s | %(levelname)-7s | %(name)s | %(message)s"_DATEFMT = "%Y-%m-%d %H:%M:%S"def setup_logger(level: int = logging.INFO) -> logging.Logger:    global _configured    logger = logging.getLogger(CONFIG.logger_name)    if _configured:        return logger    logger.setLevel(level)    logger.propagate = False    fmt = logging.Formatter(_FORMAT, datefmt=_DATEFMT)    ch = logging.StreamHandler()    ch.setFormatter(fmt)    logger.addHandler(ch)    try:        LOGS_DIR.mkdir(parents=True, exist_ok=True)        fh = RotatingFileHandler(            LOGS_DIR / "safr.log",            maxBytes=1_000_000, backupCount=3, encoding="utf-8",        )        fh.setFormatter(fmt)        logger.addHandler(fh)    except OSError:        pass    _configured = True    return loggerdef get_logger(name: str | None = None) -> logging.Logger:    base = CONFIG.logger_name    return logging.getLogger(f"{base}.{name}") if name else logging.getLogger(base)